arguments.file_text:
namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Name { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics including statistics." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Exploration of past events, societies, and civilizations." },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and computer science education. She holds a PhD from MIT.", IsFeatured = true, DepartmentName = "Computer Science" },
            new() { Id = 2, DepartmentId = 1, CourseCode = "CS 201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and dynamic programming.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has published over 40 papers in top CS conferences.", IsFeatured = true, DepartmentName = "Computer Science" },
            new() { Id = 3, DepartmentId = 1, CourseCode = "CS 310", Title = "Database Systems", Description = "Relational database design, SQL, transaction management, and introduction to NoSQL databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Prof. Maria Gonzalez", InstructorBio = "Prof. Gonzalez worked at Oracle for a decade before joining academia. She focuses on distributed database systems.", IsFeatured = false, DepartmentName = "Computer Science" },
            new() { Id = 4, DepartmentId = 2, CourseCode = "MATH 101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications to science and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is an award-winning educator who has taught calculus for over 20 years.", IsFeatured = true, DepartmentName = "Mathematics" },
            new() { Id = 5, DepartmentId = 2, CourseCode = "MATH 230", Title = "Linear Algebra", Description = "Vector spaces, matrices, eigenvalues, and linear transformations with applications.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Anna Petrov", InstructorBio = "Dr. Petrov's research focuses on numerical linear algebra and scientific computing.", IsFeatured = false, DepartmentName = "Mathematics" },
            new() { Id = 6, DepartmentId = 3, CourseCode = "ENG 101", Title = "Composition & Rhetoric", Description = "Develop college-level writing skills through essays, research papers, and peer review workshops.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Prof. David Thompson", InstructorBio = "Prof. Thompson is a published author and has directed the university writing center for eight years.", IsFeatured = false, DepartmentName = "English" },
            new() { Id = 7, DepartmentId = 3, CourseCode = "ENG 250", Title = "American Literature", Description = "Survey of major works in American literature from the colonial period to the present.", Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Michelle Adams", InstructorBio = "Dr. Adams specializes in 20th-century American fiction and has authored three books on the subject.", IsFeatured = true, DepartmentName = "English" },
            new() { Id = 8, DepartmentId = 4, CourseCode = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Thu Lab 2:00–4:50 PM", InstructorName = "Dr. Kevin O'Brien", InstructorBio = "Dr. O'Brien is an experimental physicist with research in condensed matter physics.", IsFeatured = false, DepartmentName = "Physics" },
            new() { Id = 9, DepartmentId = 4, CourseCode = "PHYS 220", Title = "Electromagnetism", Description = "Electric and magnetic fields, Maxwell's equations, and electromagnetic waves.", Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM + Fri Lab 1:00–3:50 PM", InstructorName = "Dr. Lisa Nakamura", InstructorBio = "Dr. Nakamura's research involves photonics and she holds multiple patents in optical communications.", IsFeatured = false, DepartmentName = "Physics" },
            new() { Id = 10, DepartmentId = 5, CourseCode = "HIST 101", Title = "World Civilizations", Description = "A global survey of major civilizations from antiquity to the early modern period.", Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", InstructorName = "Dr. William Harris", InstructorBio = "Dr. Harris is a historian of ancient Rome and the Mediterranean world with numerous acclaimed publications.", IsFeatured = false, DepartmentName = "History" },
            new() { Id = 11, DepartmentId = 5, CourseCode = "HIST 305", Title = "Modern European History", Description = "Europe from the French Revolution through the Cold War, examining political, social, and cultural transformations.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Claire Dubois", InstructorBio = "Dr. Dubois is a specialist in French and German history, with a focus on nationalism and identity.", IsFeatured = false, DepartmentName = "History" },
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database.
        return true;
    }
}

