+@inject CatalogService CatalogService
+
+<PageTitle>Enrollment Request - University Course Catalog</PageTitle>
+
+<div class="container">
+    <h1>Enrollment Request</h1>
+    <p>Submit this form to request enrollment in a course. You will receive confirmation via your university email.</p>
+
+    @if (submitted)
+    {
+        <div class="success-message">
+            <h2>Request Submitted</h2>
+            <p>Thank you, <strong>@model.FullName</strong>. Your enrollment request for
+                <strong>@(courses.FirstOrDefault(c => c.Id == model.CourseId)?.Title)</strong>
+                has been received.</p>
+            <a href="/courses" class="btn btn-secondary">Browse More Courses</a>
+        </div>
+    }
+    else
+    {
+        <form method="post" @formname="enrollment" @onsubmit="HandleSubmit" class="enrollment-form">
+            <AntiforgeryToken />
+
+            <div class="form-group">
+                <label for="fullName">Full Name</label>
+                <input type="text" id="fullName" name="model.FullName" value="@model.FullName" required />
+                @if (errors.ContainsKey(nameof(model.FullName)))
+                {
+                    <span class="field-error">@errors[nameof(model.FullName)]</span>
+                }
+            </div>
+
+            <div class="form-group">
+                <label for="studentId">Student ID</label>
+                <input type="text" id="studentId" name="model.StudentId" value="@model.StudentId"
+                       placeholder="e.g. ABC12345" required />
+                @if (errors.ContainsKey(nameof(model.StudentId)))
+                {
+                    <span class="field-error">@errors[nameof(model.StudentId)]</span>
+                }
+            </div>
+
+            <div class="form-group">
+                <label for="courseId">Course</label>
+                <select id="courseId" name="model.CourseId" required>
+                    <option value="">-- Select a Course --</option>
+                    @foreach (var course in courses)
+                    {
+                        <option value="@course.Id" selected="@(model.CourseId == course.Id)">@course.CourseCode - @course.Title</option>
+                    }
+                </select>
+                @if (errors.ContainsKey(nameof(model.CourseId)))
+                {
+                    <span class="field-error">@errors[nameof(model.CourseId)]</span>
+                }
+            </div>
+
+            <button type="submit" class="btn btn-primary">Submit Request</button>
+        </form>
+    }
+</div>
+
+@code {
+    [SupplyParameterFromQuery] public int? CourseId { get; set; }
+    [SupplyParameterFromForm] private EnrollmentRequest model { get; set; } = new();
+
+    private List<Course> courses = new();
+    private bool submitted;
+    private Dictionary<string, string> errors = new();
+
+    protected override void OnInitialized()
+    {
+        courses = CatalogService.GetAllCourses();
+        if (CourseId.HasValue && model.CourseId == 0)
+        {
+            model.CourseId = CourseId.Value;
+        }
+    }
+
+    private void HandleSubmit()
+    {
+        errors.Clear();
+        var validationResults = new List<System.ComponentModel.DataAnnotations.ValidationResult>();
+        var context = new System.ComponentModel.DataAnnotations.ValidationContext(model);
+        if (!System.ComponentModel.DataAnnotations.Validator.TryValidateObject(model, context, validationResults, true))
+        {
+            foreach (var result in validationResults)
+            {
+                foreach (var member in result.MemberNames)
+                {
+                    errors[member] = result.ErrorMessage ?? "Invalid value.";
+                }
+            }
+            return;
+        }
+
+        CatalogService.SubmitEnrollmentRequest(model);
+        submitted = true;
+    }
+}
+

