@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="hero">
        <h1>University Course Catalog</h1>
        <p>Explore our departments and courses. Find the right classes for your academic journey.</p>
    </div>

    <section class="featured-section">
        <h2>Featured Courses</h2>
        <div class="course-grid">
            @foreach (var course in featuredCourses)
            {
                <div class="course-card">
                    <span class="badge">@course.CourseCode</span>
                    <h3><a href="/courses/@course.Id">@course.Title</a></h3>
                    <p>@course.DepartmentName &bull; @course.Credits credits</p>
                    <p class="instructor">@course.InstructorName</p>
                </div>
            }
        </div>
    </section>

    <section class="departments-section">
        <h2>Departments</h2>
        <div class="dept-grid">
            @foreach (var dept in departments)
            {
                <div class="dept-card">
                    <h3><a href="/courses?departmentId=@dept.Id">@dept.Name</a></h3>
                    <p>@dept.Description</p>
                </div>
            }
        </div>
    </section>

    <div class="cta">
        <a href="/enroll" class="btn btn-primary">Request Enrollment</a>
        <a href="/courses" class="btn btn-secondary">Browse All Courses</a>
    </div>
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetAllDepartments();
    }
}

