.btn-primary {
    color: #fff;
    background-color: #1b6ec2;
    border-color: #1861ac;
}

.btn:focus, .btn:active:focus, .btn-link.nav-link:focus, .form-control:focus, .form-check-input:focus {
  box-shadow: 0 0 0 0.1rem white, 0 0 0 0.25rem #258cfb;
}

.content {
    padding-top: 1.1rem;
}

h1:focus {
    outline: none;
}

.valid.modified:not([type=checkbox]) {
    outline: 1px solid #26b050;
}

.invalid {
    outline: 1px solid #e50000;
}

.validation-message {
    color: #e50000;
}

.blazor-error-boundary {
    background: url(data:image/svg+xml;base64,) no-repeat 1rem/1.8rem, #b32121;
    padding: 1rem 1rem 1rem 3.7rem;
    color: white;
}

    .blazor-error-boundary::after {
        content: "An error has occurred."
    }

.darker-border-checkbox.form-check-input {
    border-color: #929292;
}

/* ===== University Course Catalog Styles ===== */

.container {
    max-width: 1100px;
    margin: 0 auto;
}

.hero {
    text-align: center;
    padding: 2rem 1rem;
    background: linear-gradient(135deg, #1b6ec2, #0d47a1);
    color: white;
    border-radius: 8px;
    margin-bottom: 2rem;
}

.hero h1 {
    margin: 0 0 0.5rem;
    font-size: 2rem;
}

.hero p {
    margin: 0;
    opacity: 0.9;
}

/* Buttons */
.btn {
    display: inline-block;
    padding: 0.6rem 1.2rem;
    border-radius: 4px;
    text-decoration: none;
    font-weight: 500;
    cursor: pointer;
    border: none;
    font-size: 0.95rem;
}

.btn-primary {
    background-color: #1b6ec2;
    color: #fff;
}

.btn-primary:hover {
    background-color: #155a9c;
}

.btn-secondary {
    background-color: #6c757d;
    color: #fff;
}

.btn-secondary:hover {
    background-color: #565e64;
}

/* Badge */
.badge {
    display: inline-block;
    background: #e3f2fd;
    color: #1565c0;
    padding: 0.2rem 0.6rem;
    border-radius: 3px;
    font-size: 0.8rem;
    font-weight: 600;
}

/* Course Grid */
.course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.2rem;
    margin-bottom: 2rem;
}

.course-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.2rem;
    transition: box-shadow 0.2s;
}

.course-card:hover {
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
}

.course-card h3 {
    margin: 0.5rem 0 0.3rem;
    font-size: 1.1rem;
}

.course-card h3 a {
    text-decoration: none;
}

.course-card .instructor {
    color: #666;
    font-style: italic;
    margin: 0.3rem 0 0;
}

/* Department Grid */
.dept-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
    gap: 1rem;
    margin-bottom: 2rem;
}

.dept-card {
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1rem;
}

.dept-card h3 {
    margin: 0 0 0.4rem;
    font-size: 1rem;
}

.dept-card h3 a {
    text-decoration: none;
}

.dept-card p {
    margin: 0;
    font-size: 0.9rem;
    color: #555;
}

/* CTA section */
.cta {
    text-align: center;
    padding: 1.5rem 0;
    display: flex;
    gap: 1rem;
    justify-content: center;
}

/* Sections */
.featured-section h2,
.departments-section h2 {
    border-bottom: 2px solid #1b6ec2;
    padding-bottom: 0.4rem;
    margin-bottom: 1rem;
}

