+.badge {
+    display: inline-block;
+    background: #e3f2fd;
+    color: #1565c0;
+    padding: 0.2rem 0.6rem;
+    border-radius: 3px;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+/* Course Grid */
+.course-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
+    gap: 1.2rem;
+    margin-bottom: 2rem;
+}
+
+.course-card {
+    border: 1px solid #e0e0e0;
+    border-radius: 8px;
+    padding: 1.2rem;
+    transition: box-shadow 0.2s;
+}
+
+.course-card:hover {
+    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
+}
+
+.course-card h3 {
+    margin: 0.5rem 0 0.3rem;
+    font-size: 1.1rem;
+}
+
+.course-card h3 a {
+    text-decoration: none;
+}
+
+.course-card .instructor {
+    color: #666;
+    font-style: italic;
+    margin: 0.3rem 0 0;
+}
+
+/* Department Grid */
+.dept-grid {
+    display: grid;
+    grid-template-columns: repeat(auto-fill, minmax(220px, 1fr));
+    gap: 1rem;
+    margin-bottom: 2rem;
+}
+
+.dept-card {
+    border: 1px solid #e0e0e0;
+    border-radius: 8px;
+    padding: 1rem;
+}
+
+.dept-card h3 {
+    margin: 0 0 0.4rem;
+    font-size: 1rem;
+}
+
+.dept-card h3 a {
+    text-decoration: none;
+}
+
+.dept-card p {
+    margin: 0;
+    font-size: 0.9rem;
+    color: #555;
+}
+
+/* CTA section */
+.cta {
+    text-align: center;
+    padding: 1.5rem 0;
+    display: flex;
+    gap: 1rem;
+    justify-content: center;
+}
+
+/* Sections */
+.featured-section h2,
+.departments-section h2 {
+    border-bottom: 2px solid #1b6ec2;
+    padding-bottom: 0.4rem;
+    margin-bottom: 1rem;
+}
+
+/* Filter Form */
+.filter-form {
+    display: flex;
+    gap: 0.8rem;
+    margin-bottom: 1.5rem;
+    flex-wrap: wrap;
+    align-items: center;
+}
+
+.filter-form input[type="text"] {
+    flex: 1;
+    min-width: 200px;
+    padding: 0.5rem 0.8rem;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+    font-size: 0.95rem;
 }

-.form-floating > .form-control-plaintext:focus::placeholder, .form-floating > .form-control:focus::placeholder {
-    text-align: start;
+.filter-form select {
+    padding: 0.5rem 0.8rem;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+    font-size: 0.95rem;
+}
+
+/* Course List */
+.course-list {
+    display: flex;
+    flex-direction: column;
+    gap: 0.8rem;
+}
+
+.course-list-item {
+    border: 1px solid #e0e0e0;
+    border-radius: 6px;
+    padding: 1rem 1.2rem;
+}
+
+.course-list-item h3 {
+    margin: 0.3rem 0;
+    font-size: 1.1rem;
+}
+
+.course-list-item h3 a {
+    text-decoration: none;
+}
+
+.course-list-item p {
+    margin: 0.2rem 0;
+    color: #555;
+    font-size: 0.9rem;
+}
+
+.course-list-item .schedule {
+    font-style: italic;
+}
+
+.no-results {
+    padding: 2rem;
+    text-align: center;
+    color: #666;
+}
+
+/* Course Detail */
+.breadcrumb {
+    margin-bottom: 1rem;
+    font-size: 0.9rem;
+}
+
+.breadcrumb a {
+    text-decoration: none;
+}
+
+.course-detail header {
+    margin-bottom: 1.5rem;
+}
+
+.course-detail header h1 {
+    margin: 0.4rem 0 0;
+}
+
+.detail-grid {
+    display: grid;
+    grid-template-columns: 1fr 300px;
+    gap: 2rem;
+}
+
+@media (max-width: 768px) {
+    .detail-grid {
+        grid-template-columns: 1fr;
+    }
+}
+
+.detail-main section {
+    margin-bottom: 1.5rem;
+}
+
+.detail-main h2 {
+    font-size: 1.2rem;
+    border-bottom: 1px solid #eee;
+    padding-bottom: 0.3rem;
+}
+
+.detail-sidebar .info-card {
+    border: 1px solid #e0e0e0;
+    border-radius: 8px;
+    padding: 1.2rem;
+    background: #f8f9fa;
+}
+
+.info-card h3 {
+    margin: 0 0 0.8rem;
+    font-size: 1rem;
+}
+
+.info-card dl {
+    margin: 0 0 1rem;
+}
+
+.info-card dt {
+    font-weight: 600;
+    font-size: 0.85rem;
+    color: #555;
+    margin-top: 0.6rem;
+}
+
+.info-card dd {
+    margin: 0.1rem 0 0;
+}
+
+/* Enrollment Form */
+.enrollment-form {
+    max-width: 500px;
+}
+
+.form-group {
+    margin-bottom: 1.2rem;
+}
+
+.form-group label {
+    display: block;
+    font-weight: 600;
+    margin-bottom: 0.3rem;
+}
+
+.form-group input,
+.form-group select {
+    width: 100%;
+    padding: 0.5rem 0.8rem;
+    border: 1px solid #ccc;
+    border-radius: 4px;
+    font-size: 0.95rem;
+}
+
+.field-error {
+    display: block;
+    color: #e50000;
+    font-size: 0.85rem;
+    margin-top: 0.2rem;
+}
+
+.success-message {
+    background: #e8f5e9;
+    border: 1px solid #a5d6a7;
+    border-radius: 8px;
+    padding: 1.5rem;
+}
+
+.success-message h2 {
+    color: #2e7d32;
+    margin: 0 0 0.5rem;
 }

